**MCP server route or PowerShell direct?**

I don't have live file system access—I'm a text interface. But here's what you do:

**Option 1: PowerShell (direct)**
```powershell
# Read dream_journal and dump symbol state
$entries = Get-ChildItem data/dream_journal/ -Filter *.json | ForEach-Object { Get-Content $_.FullName | ConvertFrom-Json }

# Build symbol map
$symbols = @{}
foreach ($entry in $entries) {
    foreach ($tag in $entry.tags) {
        if (-not $symbols[$tag]) { $symbols[$tag] = @{count = 0; edges = @{} } }
        $symbols[$tag].count++
    }
    # Build co-occurrence
    for ($i = 0; $i -lt $entry.tags.Count; $i++) {
        for ($j = $i + 1; $j -lt $entry.tags.Count; $j++) {
            $tag1, $tag2 = $entry.tags[$i], $entry.tags[$j]
            $symbols[$tag1].edges[$tag2]++
            $symbols[$tag2].edges[$tag1]++
        }
    }
}

# Output
$symbols | ConvertTo-Json
```

**Option 2: MCP server route**
Add to `apps/lantern-garage/routes/` a new file `mesh-status.js`:
```javascript
module.exports = async (req, res) => {
  const fs = require('fs').promises;
  const path = require('path');

  const dir = path.join(__dirname, '../../data/dream_journal');
  const files = await fs.readdir(dir);
  const entries = await Promise.all(
    files.map(f => fs.readFile(path.join(dir, f), 'utf8').then(JSON.parse))
  );

  // Build mesh
  const mesh = {};
  entries.forEach(e => {
    e.tags?.forEach(tag => {
      if (!mesh[tag]) mesh[tag] = { count: 0, edges: {} };
      mesh[tag].count++;
    });
  });

  res.json(mesh);
};
```

Then hit `GET /api/mesh-status`.

